#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-27

# ============================================================================
# AskUserQuestion Schema Conformance Tests
# ============================================================================
# Validates every AskUserQuestion( call authored in skill .md files against the
# Claude Code tool schema. A schema-invalid call causes an InputValidationError
# at the harness — the picker never renders and the skill stalls ("stuck"),
# which is exactly the failure misdiagnosed as a "CC 2.1.139 input bug" in
# orchestkit#1795. The real cause was schema drift: a `markdown` key (invalid)
# and >4-option questions. This test prevents regression.
#
# NOTE: the `preview` field is still ALLOWED by the schema (rule 3 keeps it in
# the permitted set), but skills no longer USE it: on current CC, a `preview`
# forces a side-by-side picker layout where up/down keyboard nav is dead
# (confirmed 2026-05-28), so skills standardize on plain label + description.
# These tests intentionally do NOT forbid `preview` — the schema permits it; we
# just stopped authoring it. Rules below stay as schema-conformance gates.
#
# Rules enforced (per https://code.claude.com/docs/en/agent-sdk/user-input):
#   1. Each question has 2-4 options          (minItems 2, maxItems 4)
#   2. Each call has 1-4 questions             (maxItems 4)
#   3. Option fields ⊆ {label, description, preview}  (additionalProperties:false)
#      → the legacy `markdown` key is invalid; `preview` is permitted but unused
#   4. No `preview` on a multiSelect question  (previews are single-select only)
#
# Usage: ./test-askuserquestion-schema.sh [--verbose]
# Exit codes: 0 = all pass, 1 = violations found
# ============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../../.." && pwd)}"
SKILLS_DIR="$PROJECT_ROOT/src/skills"
VERBOSE="${1:-}"

if [[ -t 1 ]]; then
    RED='\033[0;31m'; GREEN='\033[0;32m'; CYAN='\033[0;36m'; NC='\033[0m'
else
    RED=''; GREEN=''; CYAN=''; NC=''
fi

echo -e "${CYAN}AskUserQuestion schema conformance${NC} — scanning $SKILLS_DIR"

VERBOSE="$VERBOSE" python3 - "$SKILLS_DIR" <<'PYEOF'
import os, re, sys

skills_dir = sys.argv[1]
verbose = os.environ.get("VERBOSE", "") in ("--verbose", "-v")

# `preview` is schema-valid for CC but project-FORBIDDEN: it forces CC's
# side-by-side picker layout where up/down nav is dead (confirmed 2026-05-28,
# see memory feedback_askuserquestion_preview_nav_bug). Re-allow only after CC
# fixes the layout nav bug. Flagged with a dedicated message below.
VALID_OPTION_KEYS = {"label", "description"}
violations = []   # list of "file:line  message"
calls_checked = 0
questions_checked = 0


def scan_string_aware(text, start, open_ch, close_ch):
    """Return index of the close_ch matching the open_ch at `start`,
    ignoring brackets inside double-quoted strings (handles \\" and \\n)."""
    depth = 0
    i = start
    in_str = False
    while i < len(text):
        c = text[i]
        if in_str:
            if c == "\\":
                i += 2
                continue
            if c == '"':
                in_str = False
        else:
            if c == '"':
                in_str = True
            elif c == open_ch:
                depth += 1
            elif c == close_ch:
                depth -= 1
                if depth == 0:
                    return i
        i += 1
    return -1


def top_level_object_keys(obj_body):
    """Given the inside of a {...} object (without the outer braces), return the
    list of top-level key names (strings immediately followed by ':' at depth 0),
    string-aware so preview content with ':' or brackets does not confuse it."""
    keys = []
    i = 0
    depth = 0
    in_str = False
    n = len(obj_body)
    while i < n:
        c = obj_body[i]
        if in_str:
            if c == "\\":
                i += 2
                continue
            if c == '"':
                in_str = False
            i += 1
            continue
        if c == '"':
            # start of a string token at this depth — capture it
            j = i + 1
            buf = []
            while j < n:
                cj = obj_body[j]
                if cj == "\\":
                    buf.append(obj_body[j:j + 2])
                    j += 2
                    continue
                if cj == '"':
                    break
                buf.append(cj)
                j += 1
            token = "".join(buf)
            # is this a key? next non-space char must be ':' and we must be at depth 0
            k = j + 1
            while k < n and obj_body[k] in " \t\n":
                k += 1
            if depth == 0 and k < n and obj_body[k] == ":":
                keys.append(token)
            i = j + 1
            continue
        if c in "{[":
            depth += 1
        elif c in "}]":
            depth -= 1
        i += 1
    return keys


def split_top_level_objects(arr_body):
    """Yield each top-level {...} object body inside an array, string-aware."""
    i = 0
    n = len(arr_body)
    in_str = False
    while i < n:
        c = arr_body[i]
        if in_str:
            if c == "\\":
                i += 2
                continue
            if c == '"':
                in_str = False
            i += 1
            continue
        if c == '"':
            in_str = True
            i += 1
            continue
        if c == "{":
            close = scan_string_aware(arr_body, i, "{", "}")
            if close == -1:
                return
            yield arr_body[i + 1:close]
            i = close + 1
            continue
        i += 1


def line_of(text, idx):
    return text[:idx].count("\n") + 1


for root, _dirs, fnames in os.walk(skills_dir):
    for fn in fnames:
        if not fn.endswith(".md"):
            continue
        path = os.path.join(root, fn)
        rel = os.path.relpath(path, os.path.dirname(skills_dir))
        text = open(path, encoding="utf-8").read()

        for m in re.finditer(r"AskUserQuestion\s*\(", text):
            paren = text.index("(", m.start())
            close = scan_string_aware(text, paren, "(", ")")
            if close == -1:
                continue
            calls_checked += 1
            body = text[paren + 1:close]
            base = paren + 1  # offset of body within text

            # questions array (questions=[ ... ])
            qm = re.search(r"questions\s*=\s*\[", body)
            if not qm:
                continue
            qopen = body.index("[", qm.start())
            qclose = scan_string_aware(body, qopen, "[", "]")
            if qclose == -1:
                continue
            qarr = body[qopen + 1:qclose]

            q_objs = list(split_top_level_objects(qarr))
            if not (1 <= len(q_objs) <= 4):
                violations.append(
                    f"{rel}:{line_of(text, m.start())}  call has {len(q_objs)} questions (must be 1-4)")

            for qobj in q_objs:
                questions_checked += 1
                # locate this question's options array within qobj
                om = re.search(r'"options"\s*:\s*\[', qobj)
                if not om:
                    continue
                oopen = qobj.index("[", om.start())
                oclose = scan_string_aware(qobj, oopen, "[", "]")
                if oclose == -1:
                    continue
                oarr = qobj[oopen + 1:oclose]
                opts = list(split_top_level_objects(oarr))

                # find a label to name the question in messages
                qm2 = re.search(r'"question"\s*:\s*"([^"]{0,60})', qobj)
                qname = qm2.group(1) if qm2 else "?"
                where = f"{rel} (question: \"{qname}\")"

                if not (2 <= len(opts) <= 4):
                    violations.append(
                        f"{where}  has {len(opts)} options (must be 2-4)")

                for ob in opts:
                    keys = set(top_level_object_keys(ob))
                    # `preview` gets a dedicated message; exclude it from the
                    # generic invalid-field check so it is not double-reported.
                    bad = keys - VALID_OPTION_KEYS - {"preview"}
                    if bad:
                        violations.append(
                            f"{where}  option has invalid field(s): {sorted(bad)} "
                            f"(allowed: label, description)")
                    if "preview" in keys:
                        violations.append(
                            f"{where}  option carries a preview field — forbidden: it "
                            f"forces CC's side-by-side picker layout where up/down nav "
                            f"is dead (confirmed 2026-05-28); use label+description only")

if verbose:
    print(f"  scanned {calls_checked} AskUserQuestion call(s), "
          f"{questions_checked} question(s)")

if violations:
    print(f"\033[0;31m  FAIL\033[0m {len(violations)} schema violation(s):")
    for v in sorted(set(violations)):
        print(f"    - {v}")
    sys.exit(1)

print(f"\033[0;32m  PASS\033[0m {calls_checked} call(s) / {questions_checked} "
      f"question(s) conform to the AskUserQuestion schema")
PYEOF
